def retry_delays(base: int, attempts: int, cap: int) -> list[int]:
    if base <= 0:
        raise ValueError("base must be positive")
    if cap <= 0:
        raise ValueError("cap must be positive")
    # Support zero attempts by returning an empty list early.
    if attempts == 0:
        return []
    delays = []
    delay = base
    for _ in range(attempts):
        capped_delay = min(delay, cap)
        delays.append(capped_delay)
        delay *= 2
    return delays

